下面是如何使用`CountDownLatch`来启动JavaFX应用并保持Spring Boot应用运行：

```java
import javafx.application.Application;
import javafx.application.Platform;
import javafx.stage.Stage;
import org.springframework.boot.ApplicationArguments;
import org.springframework.boot.ApplicationRunner;
import org.springframework.stereotype.Component;

import java.util.concurrent.CountDownLatch;

@Component
public class JavaFxApplicationRunner implements ApplicationRunner {

    private static final CountDownLatch latch = new CountDownLatch(1);

    @Override
    public void run(ApplicationArguments args) throws Exception {
        Platform.startup(() -> {
            Stage stage = new Stage();
            // 设置你的Stage
            stage.show();
            stage.setOnCloseRequest(e -> latch.countDown()); // 当JavaFX窗口关闭时，释放锁
        });

        latch.await(); // 阻塞直到JavaFX应用关闭
    }

    public static void main(String[] args) {
        Application.launch(JavaFxApplication.class, args); // 启动JavaFX应用
    }
}
```

